import numpy as np

def predict(frame, action):
    next_frame = frame.copy()

    if action == 1:
        for row in range(64):
            next_frame[row, 62:64] = 0

    elif action == 3:
        for row in range(19, 23):
            for col in range(35, 39):
                if next_frame[row, col] != 2:
                    next_frame[row, col] = 9
            for col in range(41, 43):
                if next_frame[row, col] != 2:
                    next_frame[row, col] = 10

    elif action == 6:
        pass  # No changes for action 6

    return next_frame
